(function(){
  var t = (state.t||0)+1;
  state.t = t;
  var cycle = 480;
  var local = t % cycle;
  var forwardSpan = cycle*0.6;
  var dir = (local < forwardSpan) ? 1 : -1;
  state.staticDir = dir;
  var tt = (dir>0) ? (local/forwardSpan) : ((local-forwardSpan)/(cycle-forwardSpan));
  tt = Math.max(0, Math.min(1, tt));
  state.depthT = tt;
  var bp = (state.colorBurstPhase||0) + 0.004;
  state.colorBurstPhase = bp;
  var burst = 0.5+0.5*Math.sin(bp*2*Math.PI*0.25);
  state.colorBurstAmt = burst>0.85 ? (burst-0.85)/0.15 : 0;
  state.perlinX = (state.perlinX||0) + 0.01*dir;
  return state;
})();
